{"code": "import json
import re

# Get release package data from storage
package_data = locals()['var_functions.query_db:70']

# Get project data from storage  
project_data = locals()['var_functions.query_db:66']

print('Packages: ' + str(len(package_data)))
print('Projects: ' + str(len(project_data)))

# Find latest release version for each package
latest_packages = {}
for pkg in package_data:
    try:
        name = pkg['Name']
        version = pkg['Version']
        ordinal = int(pkg['Ordinal']) if pkg['Ordinal'] else 0

        if name not in latest_packages or ordinal > latest_packages[name]['ordinal']:
            latest_packages[name] = {
                'version': version,
                'ordinal': ordinal
            }
    except:
        pass

print('Latest releases: ' + str(len(latest_packages)))

# Parse star counts from project information
project_stars = {}
for project in project_data:
    info = project['Project_Information']

    # Extract repo name and stars
    stars_match = re.search(r'(\d+) stars', info)
    if stars_match:
        stars = int(stars_match.group(1))

        # Extract repo name (owner/repo format)
        repo_match = re.search(r'project ([^\s]+/[^\s]+)', info)
        if repo_match:
            repo = repo_match.group(1)
            project_stars[repo] = stars

print('Projects with stars: ' + str(len(project_stars)))
print('Sample: ' + str(list(project_stars.items())[:3]))

print('__RESULT__:')
print(json.dumps({
    'packages': len(latest_packages),
    'projects': len(project_stars)
}))"}

